"use client";

import React from "react";
import { cn } from "@/lib/utils";

interface SaillySignalLogoProps {
  className?: string;
  size?: "sm" | "md" | "lg" | "xl";
  animated?: boolean;
}

const sizes: Record<string, string> = {
  sm: "w-8 h-8",
  md: "w-12 h-12",
  lg: "w-16 h-16",
  xl: "w-32 h-32",
};

export function SaillySignalLogo({
  className,
  size = "md",
  animated = true,
}: SaillySignalLogoProps) {
  return (
    <div className={cn("relative flex items-center justify-center select-none", sizes[size], className)}>
      <svg
        viewBox="0 0 100 100"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        className={cn("w-full h-full", animated && "signal-logo-animated")}
      >
        {/* Brand gradient — matches existing Sailly palette */}
        <defs>
          <linearGradient id="signalGradient" x1="0%" y1="50%" x2="100%" y2="50%">
            <stop offset="0%" stopColor="rgb(255, 155, 138)" />
            <stop offset="50%" stopColor="rgb(255, 190, 140)" />
            <stop offset="100%" stopColor="rgb(255, 182, 203)" />
          </linearGradient>
        </defs>

        {/* Signal wave — two mirrored bezier curves */}
        <path
          d="M80 56 C71 33 59 33 50 56 C41 73 33 73 24 56"
          stroke="url(#signalGradient)"
          strokeWidth="9"
          strokeLinecap="round"
          strokeLinejoin="round"
          fill="none"
          className="signal-wave"
        />

        {/* Spark dot at origin */}
        <circle
          cx="18"
          cy="44"
          r="5.5"
          fill="url(#signalGradient)"
          className="signal-spark"
        />
      </svg>

      {/* CSS animation — delayed 3s */}
      <style jsx>{`
        .signal-logo-animated .signal-spark {
          animation: signalSparkPulse 3s ease-in-out infinite;
          animation-delay: 3s;
          transform-origin: 18px 44px;
        }
        .signal-logo-animated .signal-wave {
          animation: signalWaveBreathe 4s ease-in-out infinite;
          animation-delay: 3s;
          transform-origin: center;
        }
        @keyframes signalSparkPulse {
          0%, 100% {
            r: 5.5;
            opacity: 1;
          }
          50% {
            r: 7;
            opacity: 0.65;
          }
        }
        @keyframes signalWaveBreathe {
          0%, 100% {
            transform: scaleY(1);
          }
          50% {
            transform: scaleY(0.92);
          }
        }
      `}</style>
    </div>
  );
}

