"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { cn } from "@/lib/utils";
import { SaillySignalLogo } from "./sailly-signal-logo";
import { ChevronDown, Menu, X, Globe } from "lucide-react";

interface NavProps {
  dict: any;
  locale: string;
}

export default function SaillyHeaderV2({ dict, locale }: NavProps) {
  const [hasMounted, setHasMounted] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const [langOpen, setLangOpen] = useState(false);

  const pathname = usePathname();
  const router = useRouter();

  useEffect(() => setHasMounted(true), []);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    if (!hasMounted) return;
    if (mobileMenuOpen) {
      const currentScrollY = window.scrollY;
      setScrollY(currentScrollY);
      document.body.style.position = "fixed";
      document.body.style.top = `-${currentScrollY}px`;
      document.body.style.width = "100%";
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.position = "";
      document.body.style.top = "";
      document.body.style.width = "";
      document.body.style.overflow = "";
      if (scrollY > 0) window.scrollTo(0, scrollY);
    }
    return () => {
      document.body.style.position = "";
      document.body.style.top = "";
      document.body.style.width = "";
      document.body.style.overflow = "";
    };
  }, [mobileMenuOpen, hasMounted, scrollY]);

  useEffect(() => setMobileMenuOpen(false), [pathname]);

  const switchLocale = (newLocale: string) => {
    document.cookie = `NEXT_LOCALE=${newLocale}; path=/; max-age=${31536000}; samesite=lax`;
    const segments = pathname.split("/");
    if (segments.length > 1) {
      segments[1] = newLocale;
      router.push(segments.join("/"), { scroll: false });
    }
  };

  const languages = [
    { code: "de", label: "Deutsch" },
    { code: "en", label: "English" },
    { code: "tr", label: "Türkçe" },
    { code: "es", label: "Español" },
    { code: "ar", label: "العربية" },
    { code: "zh", label: "中文" },
    { code: "ru", label: "Русский" },
    { code: "pl", label: "Polski" },
    { code: "fr", label: "Français" },
    { code: "el", label: "Ελληνικά" },
    { code: "ko", label: "한국어" },
    { code: "vi", label: "Tiếng Việt" },
    { code: "th", label: "ไทย" },
  ];

  const navLinks = [
    { label: dict.nav?.product?.title ?? "Produkt", href: `/${locale}/produkt` },
    { label: dict.nav?.solutions?.title ?? "Lösungen", href: `/${locale}/loesungen` },
    { label: dict.nav?.pricing ?? "Preise", href: `/${locale}/preise` },
  ];

  if (!hasMounted) {
    return (
      <header className="fixed top-0 w-full z-[100] px-4 sm:px-6 py-4 bg-white border-b border-transparent">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <SaillySignalLogo size="sm" animated={false} />
            <span className="font-logo text-2xl text-[#f97e70] pb-1">Sailly</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="p-3 text-slate-700"><Menu size={24} /></div>
          </div>
        </div>
      </header>
    );
  }

  return (
    <header
      className={cn(
        "fixed top-0 w-full z-[100] transition-all duration-300 px-4 sm:px-6 py-3",
        scrolled
          ? "bg-white/95 backdrop-blur-md border-b border-slate-100 shadow-sm"
          : "bg-white border-b border-transparent"
      )}
    >
      <div className="max-w-7xl mx-auto flex items-center justify-between">
        {/* Logo */}
        <Link href={`/${locale}`} className="flex items-center gap-3 relative z-50 group">
          <SaillySignalLogo size="sm" />
          <span className="font-logo text-2xl text-[#f97e70] pb-1 hidden sm:inline-block">
            Sailly
          </span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-1">
          {navLinks.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className={cn(
                "px-4 py-2 text-sm font-medium rounded-full transition-colors",
                pathname === link.href
                  ? "text-primary bg-primary/10"
                  : "text-slate-600 hover:text-slate-900 hover:bg-slate-50"
              )}
            >
              {link.label}
            </Link>
          ))}
        </nav>

        {/* Actions */}
        <div className="flex items-center gap-2 sm:gap-3">
          {/* Login — desktop only */}
          <Link
            href={`/${locale}/login`}
            className="hidden sm:inline-flex text-sm font-medium text-slate-600 hover:text-slate-900 transition-colors"
          >
            Anmelden
          </Link>

          {/* Language Switcher */}
          <div className="relative">
            <button
              onClick={() => setLangOpen(!langOpen)}
              className="flex items-center gap-1 px-2.5 py-1.5 text-xs font-medium rounded-full bg-slate-100 border border-slate-200 text-slate-600 hover:text-slate-900 transition-all min-h-[44px] min-w-[44px] justify-center"
              aria-label="Select language"
            >
              <Globe className="w-3.5 h-3.5" />
              <span className="hidden sm:inline">{locale.toUpperCase()}</span>
              <ChevronDown className="w-3 h-3 opacity-50" />
            </button>
            {langOpen && (
              <div className="absolute top-full right-0 mt-2 w-40 max-h-80 overflow-y-auto bg-white border border-slate-100 shadow-xl rounded-xl z-50">
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => {
                      switchLocale(lang.code);
                      setLangOpen(false);
                      setMobileMenuOpen(false);
                    }}
                    className={cn(
                      "w-full text-left px-4 py-2.5 text-sm font-medium transition-colors flex items-center justify-between",
                      locale === lang.code
                        ? "bg-primary/10 text-primary font-bold"
                        : "text-slate-700 hover:bg-slate-50"
                    )}
                  >
                    <span>{lang.label}</span>
                    <span className="text-xs text-slate-400 uppercase">{lang.code}</span>
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Mobile Menu Toggle */}
          <button
            className="lg:hidden p-3 text-slate-700 hover:text-primary transition-colors rounded-lg"
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            aria-label={mobileMenuOpen ? "Close navigation menu" : "Open navigation menu"}
            aria-expanded={mobileMenuOpen}
          >
            {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>

          {/* CTA — desktop only */}
          <Link
            href={`/${locale}/demo`}
            className="hidden lg:inline-flex items-center justify-center bg-primary text-white text-sm font-bold px-5 py-2.5 rounded-full hover:bg-primary/90 transition-all shadow-lg shadow-primary/20"
          >
            {dict.nav?.demo ?? "Demo anfragen"}
          </Link>
        </div>
      </div>

      {/* Mobile Menu */}
      <nav
        className={cn(
          "fixed left-0 right-0 bg-white z-[90] p-6 overflow-y-auto lg:hidden border-t border-slate-100 transition-all duration-300 ease-out",
          mobileMenuOpen
            ? "translate-y-0 opacity-100 pointer-events-auto"
            : "translate-y-[-100%] opacity-0 pointer-events-none"
        )}
        style={{
          top: "72px",
          bottom: 0,
          WebkitOverflowScrolling: "touch",
          overscrollBehavior: "contain",
        }}
        role="navigation"
        aria-label="Mobile Navigation"
        aria-hidden={!mobileMenuOpen}
      >
        <div className="flex flex-col gap-6">
          {navLinks.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className="text-xl font-bold text-slate-900 py-2"
              onClick={() => setMobileMenuOpen(false)}
            >
              {link.label}
            </Link>
          ))}

          <div className="pt-6 border-t border-slate-100 flex flex-col gap-3">
            <Link
              href={`/${locale}/login`}
              className="block w-full text-center border border-slate-200 text-slate-700 text-lg font-medium px-6 py-4 rounded-xl hover:bg-slate-50 transition-all"
              onClick={() => setMobileMenuOpen(false)}
            >
              Anmelden
            </Link>
            <Link
              href={`/${locale}/demo`}
              className="block w-full text-center bg-primary text-white text-lg font-bold px-6 py-4 rounded-xl shadow-lg shadow-primary/20 hover:bg-primary/90 transition-all"
              onClick={() => setMobileMenuOpen(false)}
            >
              {dict.nav?.demo ?? "Demo anfragen"}
            </Link>
          </div>
        </div>
      </nav>
    </header>
  );
}

