"use client";

import React from "react";
import Link from "next/link";
import { LazyMotion, domAnimation, m } from "framer-motion";
import { ArrowRight, CheckCircle2 } from "lucide-react";
import { cn } from "@/lib/utils";

interface HeroV2Props {
  dict: any;
  locale: string;
}

export function HeroV2({ dict, locale }: HeroV2Props) {
  const hero = dict.hero ?? {};
  const badges = hero.badges ?? {};

  return (
    <LazyMotion features={domAnimation}>
      <section className="bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 pt-24 pb-16 lg:pt-32 lg:pb-24">
          <div className="grid lg:grid-cols-2 gap-12 lg:gap-16 items-center">
            {/* Text content */}
            <m.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
              className="space-y-6 text-center lg:text-left"
            >
              {/* Eyebrow */}
              {hero.eyebrow && (
                <p className="text-sm font-semibold text-primary uppercase tracking-wider">
                  {hero.eyebrow}
                </p>
              )}

              {/* Headline */}
              <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold tracking-tight text-slate-900 leading-[1.08]">
                {hero.title ?? "Der digitale Assistent, der Ihr Team entlastet."}
              </h1>

              {/* Subheadline */}
              <p className="text-lg sm:text-xl text-slate-500 leading-relaxed max-w-xl mx-auto lg:mx-0">
                {hero.subtitle}
              </p>

              {/* Trust badges */}
              <div className="flex flex-wrap gap-2 justify-center lg:justify-start">
                {Object.entries(badges).map(([key, label]: [string, any]) => (
                  <span
                    key={key}
                    className="inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-slate-100 text-slate-600 rounded-full"
                  >
                    <CheckCircle2 className="w-3.5 h-3.5 text-green-500" />
                    {label}
                  </span>
                ))}
              </div>

              {/* CTAs */}
              <div className="flex flex-col sm:flex-row gap-3 pt-2 justify-center lg:justify-start">
                <Link
                  href={`/${locale}/demo`}
                  className="inline-flex items-center justify-center gap-2 px-7 py-3.5 bg-primary text-white font-semibold rounded-full hover:bg-primary/90 transition-all shadow-lg shadow-primary/20 text-base"
                >
                  {hero.primary_cta ?? "Demo anfragen"}
                  <ArrowRight className="w-4 h-4" />
                </Link>
                <Link
                  href={`/${locale}/produkt`}
                  className="inline-flex items-center justify-center px-7 py-3.5 border border-slate-200 text-slate-700 font-semibold rounded-full hover:bg-slate-50 transition-all text-base"
                >
                  {hero.secondary_cta ?? "Mehr erfahren"}
                </Link>
              </div>
            </m.div>

            {/* Visual side — image */}
            <m.div
              initial={{ opacity: 0, scale: 0.97 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.8, delay: 0.15 }}
              className="relative aspect-[4/3] lg:aspect-[3/4] rounded-3xl overflow-hidden bg-gradient-to-br from-slate-100 via-slate-50 to-rose-50 shadow-lg shadow-slate-200/50"
            >
              {/* Placeholder — replace with actual image */}
              <div className="absolute inset-0 flex items-center justify-center text-slate-300 text-sm">
                Hotel / Restaurant Photo
              </div>
            </m.div>
          </div>
        </div>
      </section>
    </LazyMotion>
  );
}

