            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="max-w-2xl space-y-6"
          >
            {/* Eyebrow */}
            {hero.eyebrow && (
              <p className="text-sm font-semibold text-white/80 uppercase tracking-wider">
                {hero.eyebrow}
              </p>
            )}

            {/* Headline */}
            <h1 className="text-3xl sm:text-4xl lg:text-5xl xl:text-6xl font-bold tracking-tight text-white leading-[1.08]">
              {hero.title ?? "Der digitale Assistent, der Ihr Team entlastet."}
            </h1>

            {/* Subheadline */}
            <p className="text-base sm:text-lg text-white/80 leading-relaxed max-w-xl">
              {hero.subtitle}
            </p>

            {/* Trust badges */}
            <div className="flex flex-wrap gap-2">
              {Object.entries(badges).map(([key, label]: [string, any]) => (
                <span
                  key={key}
                  className="inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-white/15 backdrop-blur-sm text-white rounded-full border border-white/20"
                >
                  <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />
                  {label}
                </span>
              ))}
            </div>

            {/* CTAs */}
            <div className="flex flex-col sm:flex-row gap-3 pt-2">
              <Link
                href={`/${locale}/demo`}
                className="inline-flex items-center justify-center gap-2 px-7 py-3.5 bg-primary text-white font-semibold rounded-full hover:bg-primary/90 transition-all shadow-lg shadow-primary/20 text-base"
              >
                {hero.primary_cta ?? "Demo anfragen"}
                <ArrowRight className="w-4 h-4" />
              </Link>
              <Link
                href={`/${locale}/produkt`}
                className="inline-flex items-center justify-center px-7 py-3.5 bg-white/15 backdrop-blur-sm text-white font-semibold rounded-full hover:bg-white/25 transition-all text-base border border-white/30"
              >
                {hero.secondary_cta ?? "Mehr erfahren"}
              </Link>
            </div>
          </m.div>
        </div>
      </section>
    </LazyMotion>
  );
}

